INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06570', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對變異數分析的敘述，何者錯誤？ 變異數分析主要是比較三組以上的群體平均數是否相等的一種統計假設檢定（或稱假設考驗） 方法 變異數分析的資料必須是等距或比率層次的資料 變異數分析主要是在比較不同來源的平均數 變異數分析所用的檢定統計量是F', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06571', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對於性別與文化的偏見和不敏感可能妨礙一項研究在研究方法上的品質，甚至影響該研究發現的效 度。為避免這類問題，下列做法何者正確？ 在研究工具中強調以男性為主宰的活動 在設計研究問題時，使用雙重標準 避免使用一家之主和配偶分別稱呼男性和女性 當研究僅包括一種性別時，應在標題上加以註明，且將結論推論至其他性別', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06572', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於事後回溯研究法與實驗研究法的比較，下列何者正確？ 事後回溯研究法可以操弄自變項 事後回溯研究法係在推論上找出自變項與依變項之間的關聯 實驗研究法無法操弄自變項 實驗研究法依變項本身屬性分類由研究人員決定', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06573', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '統計假設檢定（statistical hypotheses testing），如檢定虛無假設H：μ = μ。在下列那些情況下，檢', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06574', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '1 2', '["當計算的檢定統計量（test statistic）落入拒絕域（rejection region） 或危險域（critical region）", "當P值（P-value）>顯著水準α", "當P值（P-value）顯著水準α", "當計算的檢定統計量未落入危險域時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 0, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06575', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在何種情形下統計假設檢定比較容易得到「差異顯著」的結論？ 將檢定的顯著水準變小，如α  = 0.05變小為α  = 0.01 將檢定的樣本變大 將檢定的臨界點變大（右尾檢定）或變小（左尾檢定） 在檢定的顯著水準α 不變的情況下，由單尾檢定變為雙尾檢定', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06576', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關研究倫理的敘述，何者錯誤？ 抄襲與造假都是違反倫理的行為，這些違反倫理的行為有違科學，因此又稱不當科學行為 某些田野研究者基於方法論上的正當理由，而隱瞞自己研究者的身分，以避免研究對象因知道目 的而調整自己的行為，此時研究者對身分的隱瞞就不涉及倫理的爭議 絕不能強迫任何人參與研究，參與必須是自願的；研究也須告知參與者參與的內容，研究的程序 及可能的權利，並取得參與者的同意，有些情況下需得到參與者的書面同意 研究者在研究過程中可能侵犯研究對象個人的隱私，因此研究者應保護研究對象的資訊免於曝光', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06577', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '量化資料進行統計分析時，其變項適用何者統計分析方法取決於變項的測量尺度。下列敘述何者 錯誤？ 類別尺度的變項只能用次數來計算類別 嚴格來說，中位數、平均數、標準差等指標只適用於等距和等比變項 順序尺度可以比較次序上的高低，但無法精確得知高低值間的差距 就等距尺度的變項而言，不同順序間的差距具有相同意義，另外還有絕對的零值', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06578', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於量化和質化研究方法的比較，下列敘述何者錯誤？ 在研究結構上，量化研究法強調事先訂定研究步驟，質化研究法是在資料蒐集後，逐步形成彈性 步驟 量化研究法最常用的理論邏輯是演繹法，質化研究法是歸納法 在調查現象的時間點上，量化研究法需稍早且事先熟悉現象，質化研究法則是稍晚且在現象熟悉 建立之後 在資料蒐集與分析的人力上，量化研究法花費較少，質化研究法花費較多', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06579', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在社會科學方法中，演繹取向（deductive approach）的研究步驟是：', '["問卷→施測→變項→概念→理論", "施測→問卷→變項→概念→理論", "理論→概念→變項→問卷→施測", "概念→理論→問卷→施測→變項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "4fdc7efa9f3b", "answer_pdf_sha1": "b831570213f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
